        assert 3 * (a + A) == tot;
        assert tot == 3 * des;
        assert a + A == des;
      }
    }
    return false;
  }
  assert (des - a) + (des - b) + (des - c) == n by {
    assert 3 * des == tot;
  }

  return true;
}

```

